-- Name: v_task_runs; Type: VIEW; Schema: public; Owner: metabase_user
--

CREATE VIEW public.v_task_runs AS
 SELECT task_run.id,
    task_run.run_type,
    task_run.entity_type,
    task_run.entity_id,
        CASE
            WHEN ((task_run.entity_type)::text = 'database'::text) THEN ('database_'::text || task_run.entity_id)
            WHEN ((task_run.entity_type)::text = 'card'::text) THEN ('card_'::text || task_run.entity_id)
            WHEN ((task_run.entity_type)::text = 'dashboard'::text) THEN ('dashboard_'::text || task_run.entity_id)
            ELSE (((task_run.entity_type)::text || '_'::text) || task_run.entity_id)
        END AS entity_qualified_id,
    task_run.started_at,
    task_run.ended_at,
        CASE
            WHEN (task_run.ended_at IS NOT NULL) THEN (EXTRACT(epoch FROM (task_run.ended_at - task_run.started_at)))::double precision
            ELSE NULL::double precision
        END AS duration_seconds,
    task_run.status,
    task_run.process_uuid,
    task_run.updated_at
   FROM public.task_run;


